<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing Ball Physics Playground</title>
<style>
  html, body {
    margin: 0;
    padding: 0;
    height: 100%;
    background: #0f1117;
    color: #e6e6e6;
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
  }

  h1 {
    font-size: 1.1rem;
    font-weight: 500;
    color: #8ab4f8;
    margin: 1rem 0 0.5rem;
    letter-spacing: 0.02em;
  }

  #controls {
    display: flex;
    gap: 0.6rem;
    margin-bottom: 1rem;
  }

  button {
    background: #1c2030;
    color: #e6e6e6;
    border: 1px solid #333a4d;
    border-radius: 8px;
    padding: 0.5rem 1.1rem;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s ease, transform 0.1s ease;
  }

  button:hover {
    background: #2a3145;
  }

  button:active {
    transform: scale(0.96);
  }

  #sim {
    background: radial-gradient(circle at 50% 0%, #161a26, #0a0c12);
    border: 1px solid #2a2f42;
    border-radius: 12px;
    box-shadow: 0 0 40px rgba(80, 120, 255, 0.08), inset 0 0 60px rgba(0,0,0,0.5);
    cursor: crosshair;
    display: block;
  }

  footer {
    margin-top: 0.8rem;
    font-size: 0.8rem;
    color: #666e85;
  }
</style>
</head>
<body>

<h1>Bouncing Ball Playground</h1>
<div id="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sim" width="600" height="500"></canvas>
<footer>Click the canvas to drop a ball where you click</footer>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.5;
  const RESTITUTION = 0.75;

  let balls = [];
  let running = true;
  let rafId = null;

  const COLORS = [
    '#ff6b6b', '#4ecdc4', '#ffe66d', '#a78bfa',
    '#f472b6', '#60a5fa', '#34d399', '#fb923c'
  ];
  let colorIndex = 0;

  function randRange(min, max) {
    return min + Math.random() * (max - min);
  }

  function addBall(x, y, vx = 0, vy = 0, r) {
    if (r === undefined || r === null) {
      r = randRange(12, 26);
    }
    // Clamp spawn position inside canvas bounds.
    x = Math.min(Math.max(x, r), W - r);
    y = Math.min(Math.max(y, r), H - r);
    const ball = {
      x, y, vx, vy, r,
      color: COLORS[colorIndex % COLORS.length]
    };
    colorIndex++;
    balls.push(ball);
    draw();
    return ball;
  }

  function clear() {
    balls = [];
    draw();
  }

  function step(dt = 1) {
    for (const b of balls) {
      // Gravity
      b.vy += GRAVITY * dt;

      // Integrate position
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // Bounce off left/right edges, clamp inside bounds
      if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx = -b.vx * RESTITUTION;
      } else if (b.x + b.r > W) {
        b.x = W - b.r;
        b.vx = -b.vx * RESTITUTION;
      }

      // Bounce off top/bottom edges, clamp inside bounds
      if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy = -b.vy * RESTITUTION;
      } else if (b.y + b.r > H) {
        b.y = H - b.r;
        b.vy = -b.vy * RESTITUTION;
      }
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    // subtle floor line
    ctx.strokeStyle = 'rgba(255,255,255,0.05)';
    ctx.beginPath();
    ctx.moveTo(0, H - 1);
    ctx.lineTo(W, H - 1);
    ctx.stroke();

    for (const b of balls) {
      const gradient = ctx.createRadialGradient(
        b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1,
        b.x, b.y, b.r
      );
      gradient.addColorStop(0, lighten(b.color));
      gradient.addColorStop(1, b.color);

      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = gradient;
      ctx.fill();
      ctx.lineWidth = 1;
      ctx.strokeStyle = 'rgba(0,0,0,0.3)';
      ctx.stroke();
    }
  }

  function lighten(hex) {
    const c = hex.replace('#', '');
    const r = Math.min(255, parseInt(c.substr(0, 2), 16) + 60);
    const g = Math.min(255, parseInt(c.substr(2, 2), 16) + 60);
    const b = Math.min(255, parseInt(c.substr(4, 2), 16) + 60);
    return `rgb(${r},${g},${b})`;
  }

  function loop() {
    if (running) {
      step(1);
    }
    rafId = requestAnimationFrame(loop);
  }

  // --- UI wiring ---

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    addBall(x, y, randRange(-3, 3), randRange(-2, 2));
  });

  document.getElementById('drop').addEventListener('click', () => {
    const x = randRange(50, W - 50);
    addBall(x, 30, randRange(-2, 2), 0);
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
  });

  document.getElementById('clear').addEventListener('click', clear);

  // Seed with one ball for a lively initial view.
  addBall(W / 2, 60, 2, 0);

  draw();
  loop();

  window.sim = {
    w: W,
    h: H,
    balls: () => balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })),
    addBall,
    clear,
    step
  };
})();
</script>

</body>
</html>
